class TweetCounts {
public:
    TweetCounts() {

    }

    void recordTweet(string tweetName, int time) {
        tweetCounts[tweetName].push_back(time);
    }

    vector<int> getTweetCountsPerFrequency(string freq, string tweetName, int startTime, int endTime) {
        vector<int> result;
        if (tweetCounts.find(tweetName) == tweetCounts.end()) return result;

        vector<int>& times = tweetCounts[tweetName];
        int chunkSize;
        if (freq == "minute") chunkSize = 60;
        else if (freq == "hour") chunkSize = 3600;
        else chunkSize = 86400;

        int start = lower_bound(times.begin(), times.end(), startTime) - times.begin();
        int end = upper_bound(times.begin(), times.end(), endTime) - times.begin();

        for (int i = start; i < end; i += chunkSize) {
            int j = min(i + chunkSize, end);
            result.push_back(j - i);
        }
        return result;
    }
private:
    unordered_map<string, vector<int>> tweetCounts;
};

```
